import{_ as s,c as i,o as e,aj as t}from"./chunks/framework.VtnL2jmu.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"踩坑记录/Java 容器中 HTTPS 调用失败问题记录.md","filePath":"踩坑记录/Java 容器中 HTTPS 调用失败问题记录.md"}'),l={name:"踩坑记录/Java 容器中 HTTPS 调用失败问题记录.md"};function n(h,a,r,d,o,p){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h2 id="java-容器中-https-调用失败问题记录" tabindex="-1">Java 容器中 HTTPS 调用失败问题记录 <a class="header-anchor" href="#java-容器中-https-调用失败问题记录" aria-label="Permalink to “Java 容器中 HTTPS 调用失败问题记录”">​</a></h2><h3 id="问题现象" tabindex="-1">问题现象 <a class="header-anchor" href="#问题现象" aria-label="Permalink to “问题现象”">​</a></h3><ul><li>本地开发环境调用第三方支付接口正常</li><li>部署到 Docker 容器后，调用失败，报错：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>javax.net.ssl.SSLHandshakeException: Received fatal alert: handshake_failure</span></span></code></pre></div></li></ul><h3 id="问题原因" tabindex="-1">问题原因 <a class="header-anchor" href="#问题原因" aria-label="Permalink to “问题原因”">​</a></h3><ul><li>第三方支付服务器要求 <strong>TLS 1.2</strong> 协议</li><li>Docker 容器中的 JVM 默认没有正确启用 TLS 1.2，导致握手失败</li></ul><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to “解决方案”">​</a></h3><p>在 Dockerfile 的启动命令中添加 JVM 参数，强制指定 TLS 协议版本：</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;java&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &quot;-Dhttps.protocols=TLSv1.2,TLSv1.1,TLSv1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &quot;-Djdk.tls.client.protocols=TLSv1.2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &quot;-jar&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &quot;app.jar&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><h3 id="参数说明" tabindex="-1">参数说明 <a class="header-anchor" href="#参数说明" aria-label="Permalink to “参数说明”">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td><code>-Dhttps.protocols</code></td><td>设置 HttpsURLConnection 可用的 TLS 协议</td></tr><tr><td><code>-Djdk.tls.client.protocols</code></td><td>强制 TLS 客户端使用指定的协议版本</td></tr></tbody></table><h3 id="验证结果" tabindex="-1">验证结果 <a class="header-anchor" href="#验证结果" aria-label="Permalink to “验证结果”">​</a></h3><p>添加参数后重新构建镜像，下单功能恢复正常 ✅</p><h3 id="备注" tabindex="-1">备注 <a class="header-anchor" href="#备注" aria-label="Permalink to “备注”">​</a></h3><ul><li>如果问题依然存在，可以尝试将基础镜像从 Alpine 版本换为标准版本（如 <code>eclipse-temurin:8-jre</code>），CA 证书更完整</li><li>添加 <code>-Djavax.net.debug=ssl:handshake:verbose</code> 可输出详细握手日志用于排查</li></ul>`,14)])])}const g=s(l,[["render",n]]);export{c as __pageData,g as default};
